#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    int val;
    struct Node *left;
    struct Node *right;
} Node;

Node* getNode(Node **pool, int *cnt, int val) {
    Node *node = (Node*)malloc(sizeof(Node));
    node->val = val;
    node->left = node->right = NULL;
    pool[(*cnt)++] = node;
    return node;
}

void reverseInorder(Node *root, int K, int *cnt, int *answer) {
    if (!root || *cnt >= K) return;
    reverseInorder(root->right, K, cnt, answer);
    if (++(*cnt) == K) {
        *answer = root->val;
        return;
    }
    reverseInorder(root->left, K, cnt, answer);
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        // map value -> node pointer (simple array, values ≤ 100000)
        static Node *nodeMap[100001];
        static int isChild[100001];
        memset(nodeMap, 0, sizeof(nodeMap));
        memset(isChild, 0, sizeof(isChild));
        Node *pool[100000];
        int poolCnt = 0;
        for (int i = 0; i < N - 1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            if (!nodeMap[p]) nodeMap[p] = getNode(pool, &poolCnt, p);
            if (!nodeMap[c]) nodeMap[c] = getNode(pool, &poolCnt, c);
            if (dir == 'L') nodeMap[p]->left = nodeMap[c];
            else nodeMap[p]->right = nodeMap[c];
            isChild[c] = 1;
        }
        // find root (the node that never appeared as child)
        Node *root = NULL;
        for (int i = 0; i <= 100000; ++i) {
            if (nodeMap[i] && !isChild[i]) { root = nodeMap[i]; break; }
        }
        int cnt = 0, ans = -1;
        reverseInorder(root, K, &cnt, &ans);
        printf("%d\n", ans);
        // free allocated nodes (optional in contest environment)
        for (int i = 0; i < poolCnt; ++i) free(pool[i]);
    }
    return 0;
}

