#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node *left, *right;
    Node(int v) : val(v), left(nullptr), right(nullptr) {}
};

void reverseInorder(Node* root, int K, int &cnt, int &ans) {
    if (!root || cnt >= K) return;
    reverseInorder(root->right, K, cnt, ans);
    if (++cnt == K) { ans = root->val; return; }
    reverseInorder(root->left, K, cnt, ans);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        int N, K; cin>>N>>K;
        unordered_map<int, Node*> mp;
        unordered_set<int> childSet;
        for(int i=0;i<N-1;++i){
            int p,c; char dir; cin>>p>>c>>dir;
            if(mp.find(p)==mp.end()) mp[p]=new Node(p);
            if(mp.find(c)==mp.end()) mp[c]=new Node(c);
            if(dir=='L') mp[p]->left = mp[c];
            else mp[p]->right = mp[c];
            childSet.insert(c);
        }
        Node* root = nullptr;
        for(auto &kv: mp){
            if(childSet.find(kv.first)==childSet.end()) { root = kv.second; break; }
        }
        int cnt=0, ans=-1;
        reverseInorder(root, K, cnt, ans);
        cout<<ans<<"\n";
        // cleanup (optional)
        for(auto &kv: mp) delete kv.second;
    }
    return 0;
}

