import java.io.*;
import java.util.*;

class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { val = v; }
    }

    static void reverseInorder(Node node, int K, int[] cntAns) {
        if (node == null || cntAns[0] >= K) return;
        reverseInorder(node.right, K, cntAns);
        if (++cntAns[0] == K) { cntAns[1] = node.val; return; }
        reverseInorder(node.left, K, cntAns);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> child = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                map.putIfAbsent(p, new Node(p));
                map.putIfAbsent(c, new Node(c));
                Node parent = map.get(p);
                Node childNode = map.get(c);
                if (dir == 'L') parent.left = childNode; else parent.right = childNode;
                child.add(c);
            }
            Node root = null;
            for (int val : map.keySet()) {
                if (!child.contains(val)) { root = map.get(val); break; }
            }
            int[] cntAns = new int[]{0, -1}; // cntAns[0]=count, cntAns[1]=answer
            reverseInorder(root, K, cntAns);
            sb.append(cntAns[1]).append('\n');
        }
        System.out.print(sb.toString());
    }
}

