import sys

def reverse_inorder(node, K, state):
    if not node or state[0] >= K:
        return
    reverse_inorder(node.right, K, state)
    state[0] += 1
    if state[0] == K:
        state[1] = node.val
        return
    reverse_inorder(node.left, K, state)

class Node:
    __slots__ = ('val', 'left', 'right')
    def __init__(self, v):
        self.val = v
        self.left = None
        self.right = None

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N, K = map(int, next(it).split())
        nodes = {}
        children = set()
        for _ in range(N-1):
            p, c, d = next(it).split()
            p = int(p); c = int(c)
            if p not in nodes:
                nodes[p] = Node(p)
            if c not in nodes:
                nodes[c] = Node(c)
            if d == 'L':
                nodes[p].left = nodes[c]
            else:
                nodes[p].right = nodes[c]
            children.add(c)
        root = None
        for val in nodes:
            if val not in children:
                root = nodes[val]
                break
        state = [0, -1]  # count, answer
        reverse_inorder(root, K, state)
        out.append(str(state[1]))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

