function reverseInorder(node, K, state) {
  if (!node || state.count >= K) return;
  reverseInorder(node.right, K, state);
  state.count++;
  if (state.count === K) { state.answer = node.val; return; }
  reverseInorder(node.left, K, state);
}
let T = parseInt(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const [Nstr, Kstr] = input[idx++].trim().split(/\s+/);
  const N = parseInt(Nstr), K = parseInt(Kstr);
  const map = new Map();
  const childSet = new Set();
  for (let i = 0; i < N - 1; i++) {
    const parts = input[idx++].trim().split(/\s+/);
    const p = parseInt(parts[0]);
    const c = parseInt(parts[1]);
    const dir = parts[2];
    if (!map.has(p)) map.set(p, new Node(p));
    if (!map.has(c)) map.set(c, new Node(c));
    const parent = map.get(p);
    const child = map.get(c);
    if (dir === 'L') parent.left = child; else parent.right = child;
    childSet.add(c);
  }
  let root = null;
  for (let [val, node] of map.entries()) {
    if (!childSet.has(val)) { root = node; break; }
  }
  const state = { count: 0, answer: -1 };
  reverseInorder(root, K, state);
  outputs.push(String(state.answer));
}
